mapper.select:
SELECT 
FROM play_history
WHERE user_id = #{userId}
ORDER BY played_time DESC
LIMIT #{limit}

mapper.delete:
DELETE FROM play_history
WHERE user_id = #{userId}
  AND id NOT IN (
      SELECT id FROM (
          SELECT id FROM play_history
          WHERE user_id = #{userId}
          ORDER BY played_time DESC
          LIMIT #{keepCount}
      ) AS keep_ids
  )
